### 2-2. Match 도메인 (`catalog: maum`)

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/match/MatchEntity.kt
@Entity
@Table(catalog = "maum", name = "match")
class MatchEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(nullable = false)
    val requesterId: String,

    @Column(nullable = false)
    val receiverId: String,

    @Column(nullable = false)
    var status: String = "PENDING", // PENDING | ACCEPTED | REJECTED | EXPIRED | CANCELED

