### 2-5. Moment 도메인 (`catalog: moment`)

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/moment/PostEntity.kt
@Entity
@Table(catalog = "moment", name = "post")
class PostEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(nullable = false)
    val authorId: String,

    @Column(nullable = true, length = 500)
    var content: String? = null,

    @Column(nullable = false)
    var mediaType: String = "NONE",  // NONE | IMAGE | AUDIO | VIDEO

    @Column(nullable = true)
    var mediaUrl: String? = null,

    @Column(nullable = false)
    var likeCount: Int = 0,

    @Column(nullable = false)
    var commentCount: Int = 0,

    @Column(nullable = false)
    var visibility: String = "PUBLIC", // PUBLIC | FOLLOWERS | PRIVATE

    @Column(nullable = false)
    var status: String = "ACTIVE",   // ACTIVE | DELETED | HIDDEN

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

### 2-6. Notification 도메인 (`catalog: notification`)

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/notification/NotificationEntity.kt
@Entity
@Table(catalog = "notification", name = "notification")
class NotificationEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(nullable = false)
    val recipientId: String,

    @Column(nullable = false)
    val type: String,   // MATCH_REQUEST | CALL_INCOMING | CHAT_MESSAGE | POST_LIKE | FOLLOW

    @Column(nullable = true)
    val actorId: String? = null,  // 알림 유발 사용자

    @Column(nullable = true)
    val referenceId: String? = null, // matchId, callId, postId 등

    @Column(nullable = false)
    var isRead: Boolean = false,

    @Column(nullable = true, length = 500)
    val payload: String? = null,  // JSON 직렬화 추가 데이터

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),
)
```

