## 5. GraphQL 스키마 초안

파일 위치: `graphql/src/main/resources/graphql/`

### 5-1. User 스키마

```graphql
# graphql/src/main/resources/graphql/user.graphqls

type User {
    id: ID!
    nickname: String!
    gender: Gender!
    age: Int!
    profileImageUrl: String
    mannerScore: Int!
    isOnline: Boolean!
    isFollowing: Boolean!
    isBlocked: Boolean!
    profile: UserProfile
    createdAt: String!
}

type UserProfile {
    introduction: String
    job: String
    height: Int
    region: String
    mbti: String
    preferGender: Gender!
    preferMinAge: Int!
    preferMaxAge: Int!
}

type SimpleUser {
    id: ID!
    nickname: String!
    profileImageUrl: String
    mannerScore: Int!
    isOnline: Boolean!
}

enum Gender {
    MALE
    FEMALE
    OTHER
    ALL
}

input UpdateUserProfileInput {
    introduction: String
    job: String
    height: Int
    region: String
    mbti: String
    preferGender: Gender
    preferMinAge: Int
    preferMaxAge: Int
}

input UpdateUserBasicInput {
    nickname: String
    profileImageUrl: String
}

extend type Query {
    me: User!
    user(userId: ID!): User
    searchUsers(keyword: String!, limit: Int, offset: Int): [SimpleUser!]!
}

extend type Mutation {
    updateUserBasic(input: UpdateUserBasicInput!): User!
    updateUserProfile(input: UpdateUserProfileInput!): UserProfile!
    followUser(targetUserId: ID!): Boolean!
    unfollowUser(targetUserId: ID!): Boolean!
    blockUser(targetUserId: ID!): Boolean!
    unblockUser(targetUserId: ID!): Boolean!
    withdrawUser: Boolean!
}
```

### 5-2. Match 스키마

```graphql
# graphql/src/main/resources/graphql/match.graphqls

type Match {
    id: ID!
    requester: SimpleUser!
    receiver: SimpleUser!
    status: MatchStatus!
    matchType: MatchType
    createdAt: String!
}

enum MatchStatus {
    PENDING
    ACCEPTED
    REJECTED
    EXPIRED
    CANCELED
}

enum MatchType {
    VOICE_CALL
    CHAT
}

input RequestMatchInput {
    receiverId: ID!
    matchType: MatchType!
}

extend type Query {
    myMatches(status: MatchStatus, limit: Int, offset: Int): [Match!]!
    matchQueueStatus: MatchQueueStatus!
}

type MatchQueueStatus {
    isWaiting: Boolean!
    waitingCount: Int!
    estimatedWaitSeconds: Int
}

extend type Mutation {
    requestMatch(input: RequestMatchInput!): Match!
    acceptMatch(matchId: ID!): Match!
    rejectMatch(matchId: ID!): Match!
    cancelMatch(matchId: ID!): Boolean!
    joinMatchQueue(matchType: MatchType!): Boolean!
    leaveMatchQueue: Boolean!
}
```

### 5-3. Call 스키마

```graphql
# graphql/src/main/resources/graphql/call.graphqls

type CallRoom {
    id: ID!
    match: Match!
    caller: SimpleUser!
    callee: SimpleUser!
    status: CallStatus!
    durationSeconds: Int
    channelId: String!
    startedAt: String
    endedAt: String
    createdAt: String!
}

enum CallStatus {
    RINGING
    IN_CALL
    ENDED
    MISSED
    DECLINED
}

type CallToken {
    callRoomId: ID!
    channelId: String!
    token: String!
    expiresAt: String!
}

input RateCallInput {
    callRoomId: ID!
    rating: Int!   # 1~5
}

extend type Query {
    callHistory(limit: Int, offset: Int): [CallRoom!]!
    activeCall: CallRoom
}

extend type Mutation {
    initiateCall(matchId: ID!): CallToken!
    acceptCall(callRoomId: ID!): CallToken!
    declineCall(callRoomId: ID!): Boolean!
    endCall(callRoomId: ID!): CallRoom!
    rateCall(input: RateCallInput!): Boolean!
}
```

### 5-4. Chat 스키마

```graphql
# graphql/src/main/resources/graphql/chat.graphqls

type ChatRoom {
    id: ID!
    partner: SimpleUser!
    status: ChatRoomStatus!
    lastMessagePreview: String
    lastMessageAt: String
    unreadCount: Int!
    createdAt: String!
}

type ChatMessage {
    id: ID!
    chatRoomId: ID!
    sender: SimpleUser!
    messageType: MessageType!
    content: String
    mediaUrl: String
    isRead: Boolean!
    sentAt: String!
}

enum ChatRoomStatus {
    ACTIVE
    CLOSED
    BLOCKED
}

enum MessageType {
    TEXT
    IMAGE
    AUDIO
    SYSTEM
}

input SendMessageInput {
    chatRoomId: ID!
    messageType: MessageType!
    content: String
    mediaUrl: String
}

extend type Query {
    myChatRooms(limit: Int, offset: Int): [ChatRoom!]!
    chatMessages(
        chatRoomId: ID!
        limit: Int
        beforeMessageId: ID   # 커서 기반 페이지네이션
    ): [ChatMessage!]!
}

extend type Mutation {
    sendMessage(input: SendMessageInput!): ChatMessage!
    readMessages(chatRoomId: ID!): Boolean!
    closeChatRoom(chatRoomId: ID!): Boolean!
}
```

### 5-5. Moment 스키마

```graphql
# graphql/src/main/resources/graphql/moment.graphqls

type Post {
    id: ID!
    author: SimpleUser!
    content: String
    mediaType: MediaType!
    mediaUrl: String
    likeCount: Int!
    commentCount: Int!
    isLiked: Boolean!
    visibility: PostVisibility!
    createdAt: String!
}

enum MediaType {
    NONE
    IMAGE
    AUDIO
    VIDEO
}

enum PostVisibility {
    PUBLIC
    FOLLOWERS
    PRIVATE
}

input CreatePostInput {
    content: String
    mediaType: MediaType!
    mediaUrl: String
    visibility: PostVisibility!
}

extend type Query {
    feed(limit: Int, offset: Int): [Post!]!
    userPosts(userId: ID!, limit: Int, offset: Int): [Post!]!
}

extend type Mutation {
    createPost(input: CreatePostInput!): Post!
    deletePost(postId: ID!): Boolean!
    likePost(postId: ID!): Boolean!
    unlikePost(postId: ID!): Boolean!
}
```

### 5-6. Notification 스키마

```graphql
# graphql/src/main/resources/graphql/notification.graphqls

type Notification {
    id: ID!
    type: NotificationType!
    actor: SimpleUser
    referenceId: String
    isRead: Boolean!
    createdAt: String!
}

enum NotificationType {
    MATCH_REQUEST
    CALL_INCOMING
    CHAT_MESSAGE
    POST_LIKE
    FOLLOW
}

extend type Query {
    notifications(limit: Int, offset: Int): [Notification!]!
