## 6. gRPC Proto 초안

파일 위치: `protobuf/src/main/proto/{도메인}/`

### 6-1. UserService Proto

```protobuf
// protobuf/src/main/proto/user/user_service.proto
syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserService {
  rpc GetUser(GetUserRequest) returns (GetUserResponse);
  rpc GetUserProfile(GetUserProfileRequest) returns (GetUserProfileResponse);
  rpc UpdateUserBasic(UpdateUserBasicRequest) returns (UpdateUserBasicResponse);
  rpc UpdateUserProfile(UpdateUserProfileRequest) returns (UpdateUserProfileResponse);
  rpc GetMannerScore(GetMannerScoreRequest) returns (GetMannerScoreResponse);
  rpc ListBlockedUsers(ListBlockedUsersRequest) returns (ListBlockedUsersResponse);
}

message UserProto {
  string id = 1;
  string nickname = 2;
  string gender = 3;
  int32 age = 4;
  optional string profile_image_url = 5;
  int32 manner_score = 6;
  string status = 7;
  string created_at = 8;
}

message GetUserRequest {
  string user_id = 1;
  string requester_id = 2; // isFollowing, isBlocked 판단용
}

message GetUserResponse {
  UserProto user = 1;
  bool is_following = 2;
  bool is_blocked = 3;
}
